app.use((req, res, next) => {
  const isSandbox = process.env.EFI_SANDBOX === 'true';
  res.locals.EFI_SANDBOX = isSandbox;
  res.locals.EFI_PAYEE_CODE = process.env.EFI_PAYEE_CODE || '';
  const official = isSandbox
    ? 'https://sandbox.efipay.com.br/v1/payment-token.js'
    : 'https://payment-token.efipay.com.br/v1/payment-token.js';
  res.locals.EFI_SCRIPT_URL = official;
  res.locals.EFI_SCRIPT_FALLBACK_URL = 'https://cdn.jsdelivr.net/gh/efipay/js-payment-token-efi/dist/payment-token-efi.min.js';
  const pagarmeKeys = getPagarmeKeys();
  res.locals.PAGARME_PUBLIC_KEY = pagarmeKeys.public || '';
  const stripeKeys = getStripeKeys();
  res.locals.STRIPE_PUBLISHABLE_KEY = stripeKeys.publishable || '';
  res.locals.CARD_PROVIDER = (stripeKeys.publishable && stripeKeys.secret) ? 'stripe' : 'pagarme';
  res.locals.STRIPE_USE_CHECKOUT = String(process.env.STRIPE_USE_CHECKOUT || '').toLowerCase() === 'true';
  res.locals.PAGARME_INSTALLMENTS_MAX = (function () {
    const n = parseInt(String(process.env.PAGARME_INSTALLMENTS_MAX || '12'), 10);
    if (!Number.isFinite(n) || n <= 0) return 12;
    return Math.max(1, Math.min(18, n));
  })();
  res.locals.PAGARME_INSTALLMENTS_FREE = (function () {
    const n = parseInt(String(process.env.PAGARME_INSTALLMENTS_FREE || String(res.locals.PAGARME_INSTALLMENTS_MAX || 12)), 10);
    if (!Number.isFinite(n) || n < 0) return Number(res.locals.PAGARME_INSTALLMENTS_MAX || 12);
    return Math.max(0, Math.min(Number(res.locals.PAGARME_INSTALLMENTS_MAX || 12), n));
  })();
  res.locals.PAGARME_INSTALLMENT_INTEREST_RATE = (function () {
    const raw = String(process.env.PAGARME_INSTALLMENT_INTEREST_RATE || '0').replace(',', '.').trim();
    const n = Number(raw);
    if (!Number.isFinite(n) || n <= 0) return 0;
    return Math.max(0, Math.min(25, n));
  })();
  next();
});

// Middleware melhorado para capturar IP real (útil quando atrás de proxy)
app.use((req, res, next) => {
    // Tentar diferentes headers para capturar o IP real
    let ip = req.headers['x-forwarded-for'] || 
             req.headers['x-real-ip'] || 
             req.headers['cf-connecting-ip'] || 
             req.headers['x-client-ip'] || 
             req.headers['x-forwarded'] || 
             req.headers['forwarded-for'] || 
             req.headers['forwarded'] ||
             req.connection.remoteAddress || 
             req.socket.remoteAddress || 
             req.ip || 
             'unknown';
    
    // Se x-forwarded-for contém múltiplos IPs, pegar o primeiro
    if (ip && ip.includes(',')) {
        ip = ip.split(',')[0].trim();
    }
    
    // Normalizar IPv6 mapeado para IPv4
    const ipNormalized = ip.replace('::ffff:', '');
    
    // Atribuir o IP real à requisição
    req.realIP = ipNormalized;
    req.ip = ipNormalized; // Também sobrescrever req.ip
    
    next();
});

const OPPUS_CLIENT_ID_COOKIE = 'oppus_cid';
const getCookieValue = (req, name) => {
  try {
    const cookieHeader = String((req && req.headers && req.headers['cookie']) || '');
    if (!cookieHeader) return '';
    const parts = cookieHeader.split(';');
    for (const part of parts) {
      const p = String(part || '').trim();
      if (!p) continue;
      const eq = p.indexOf('=');
      if (eq <= 0) continue;
      const k = p.slice(0, eq).trim();
      if (k !== name) continue;
      const raw = p.slice(eq + 1);
      try { return decodeURIComponent(raw); } catch (_) { return raw; }
    }
  } catch (_) {}
  return '';
};

const ensureClientIdCookie = (req, res) => {
  try {
    const existing = getCookieValue(req, OPPUS_CLIENT_ID_COOKIE);
    if (existing) return existing;
    let id = '';
    try {
      const c = require('crypto');
      if (c && typeof c.randomUUID === 'function') id = c.randomUUID();
    } catch (_) {}
    if (!id) id = `cid_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
    try {
      if (res && typeof res.cookie === 'function') {
        res.cookie(OPPUS_CLIENT_ID_COOKIE, id, { maxAge: 365 * 24 * 60 * 60 * 1000, httpOnly: false, sameSite: 'Lax', path: '/' });
      } else if (res && typeof res.setHeader === 'function') {
        const cookie = `${OPPUS_CLIENT_ID_COOKIE}=${encodeURIComponent(id)}; Path=/; Max-Age=${365 * 24 * 60 * 60}; SameSite=Lax`;
        res.setHeader('Set-Cookie', cookie);
      }
    } catch (_) {}
    return id;
  } catch (_) {}
  return '';
};

app.use((req, res, next) => {
  try {
    req.oppusClientId = ensureClientIdCookie(req, res);
  } catch (_) {}
  next();
});

// Middleware de autenticação Admin
const requireAdmin = (req, res, next) => {
    if (req.session && req.session.adminUser) {
        return next();
    }
    if (req.xhr || (req.headers.accept && req.headers.accept.indexOf('json') > -1)) {
        return res.status(401).json({ error: 'Unauthorized' });
    }
    return res.redirect('/login');
};

