// Helper: validar hosts permitidos para proxy de imagem
function isAllowedImageHost(urlStr) {
  try {
    const u = new URL(urlStr);
    const host = u.hostname.toLowerCase();
    return (
      host.includes('instagram') ||
      host.includes('cdninstagram') ||
      host.includes('fbcdn') ||
      host.includes('scontent')
    );
  } catch (e) {
    return false;
  }
}

// Endpoint de proxy de imagem para evitar bloqueios de CSP/Proxy
app.get('/image-proxy', async (req, res) => {
  const targetUrl = req.query.url;
  if (!targetUrl || !isAllowedImageHost(targetUrl)) {
    return res.status(400).send('Invalid image URL');
  }
  try {
    const isIg = (function () {
      try {
        const u = new URL(String(targetUrl));
        const h = String(u.hostname || '').toLowerCase();
        return h.includes('instagram') || h.includes('cdninstagram') || h.includes('fbcdn') || h.includes('scontent');
      } catch (_) {
        return false;
      }
    })();
    const response = await axios.get(targetUrl, {
      responseType: 'arraybuffer',
      timeout: 25000,
      headers: {
        'User-Agent': req.get('User-Agent') || 'Mozilla/5.0',
        'Accept': 'image/*,video/*,*/*;q=0.8',
        ...(isIg ? { 'Referer': 'https://www.instagram.com/', 'Accept-Language': 'en-US,en;q=0.9' } : {})
      }
    });
    const contentType = response.headers['content-type'] || 'image/jpeg';
    res.setHeader('Content-Type', contentType);
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Cross-Origin-Resource-Policy', 'cross-origin');
    res.setHeader('Cache-Control', 'public, max-age=300'); // 5 minutos
    return res.send(response.data);
  } catch (err) {
    console.error('Erro proxy de imagem:', err.message);
    return res.status(502).send('Failed to fetch image');
  }
});

