// API: criar cobrança Cartão via Efí
app.post('/api/efi/card-charge', async (req, res) => {
    let correlationIDSafe = '';
    let validatedValueCents = null;
    const isSandboxEnv = process.env.EFI_SANDBOX === 'true';
    try {
        const { payment_token, installments, customer, billing_address, items, total_cents, additionalInfo, profile_is_private, comment, utms: reqUtms } = req.body;
        correlationIDSafe = (function () {
            try {
                const c = String(req.body?.correlationID || '').trim();
                if (c) return c;
            } catch (_) {}
            try {
                const crypto = require('crypto');
                if (crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
            } catch (_) {}
            return `${Date.now()}-${Math.random().toString(16).slice(2)}`;
        })();

        // Validação mínima de valor (R$ 1,00 = 100 centavos)
        if (!total_cents || total_cents < 100) {
            return res.status(400).json({ 
                error: 'invalid_amount', 
                message: 'Valor mínimo para cartão de crédito é R$ 1,00.' 
            });
        }

        // Validação de Preço (Backend) - Validação Estrita para TODOS os pedidos
        const sanitizeText = (s) => {
            if (typeof s !== 'string') return s;
            return s.replace(/[\u2012-\u2015]/g, '-').replace(/[\uD800-\uDFFF]/g, '').trim();
        };

        const sanitizedAdditional = Array.isArray(additionalInfo)
            ? additionalInfo.map((item) => ({
                key: sanitizeText(String(item?.key ?? '')),
                value: sanitizeText(String(item?.value ?? '')),
              }))
            : [];
        const addInfoArr = sanitizedAdditional
            .filter((it) => typeof it.key === 'string' && it.key.trim().length > 0 && typeof it.value === 'string' && it.value.trim().length > 0)
            .map((it) => ({ key: it.key.trim(), value: it.value.trim() }));

        try {
            const cookieHeader = req.headers['cookie'] || '';
            const m = cookieHeader && cookieHeader.match(/(?:^|;\s*)tc_code=([^;]+)/);
            const tc = m && m[1] ? decodeURIComponent(m[1]) : '';
            if (tc) {
                for (let i = addInfoArr.length - 1; i >= 0; i--) {
                    if (addInfoArr[i] && addInfoArr[i].key === 'tc_code') addInfoArr.splice(i, 1);
                }
                addInfoArr.push({ key: 'tc_code', value: String(tc) });
            }
        } catch (_) {}
        const addInfoMap = addInfoArr.reduce((acc, item) => {
             const k = String(item?.key || '').trim();
             const v = String(item?.value || '').trim();
             acc[k] = v;
             return acc;
        }, {});
        
        const tipoVal = addInfoMap['tipo_servico'] || '';
        const qtdVal = Number(addInfoMap['quantidade'] || 0) || 0;
        
        let validatedPriceCents = null;

        // Tenta validar TODOS os pedidos usando pricing.js
        let verification = await verifyPrice(tipoVal, qtdVal, addInfoArr, Number(total_cents));
        if (!verification.isValid) {
            try {
                const couponCodeRaw = addInfoMap['cupom'] || addInfoMap['coupon'] || '';
                const couponCode = normalizeCouponCode(couponCodeRaw);
                if (couponCode) {
                    const profileKey = normalizeProfileKey(addInfoMap['instagram_username'] || addInfoMap['perfil'] || '');
                    const eligibility = await getCouponEligibility(couponCode, profileKey);
                    if (eligibility && eligibility.ok && eligibility.coupon) {
                        const pct = Number(eligibility.coupon.discountPercentage || 0) || 0;
                        const rate = pct > 0 ? (pct / 100) : 0;
                        if (rate > 0 && Number.isFinite(Number(verification.expectedPrice)) && Number(verification.expectedPrice) > 0) {
                            const expected = Number(verification.expectedPrice);
                            const discountVal = Math.round(expected * rate);
                            const discountedExpected = Math.max(0, expected - discountVal);
                            if (Number(total_cents) === discountedExpected) {
                                verification = { isValid: true, matchedPrice: Number(total_cents), expectedPrice: Number(total_cents), mismatchDetails: null };
                            }
                        }
                    }
                }
            } catch (_) {}
        }
        
        if (verification.isValid) {
             // Preço validado com sucesso
             validatedPriceCents = verification.matchedPrice;
        } else {
             // Se falhar, rejeita
             console.warn(`⚠️ Bloqueio de Pagamento (Cartão): Valor incorreto. Tipo=${tipoVal}, Qtd=${qtdVal}, Valor=${total_cents}, Esperado=${verification.expectedPrice}`);
             return res.status(400).json({ 
                 error: 'value_mismatch', 
                 message: 'O valor do pagamento não corresponde ao preço oficial calculado pelo sistema.' 
             });
        }

        const options = {
            sandbox: process.env.EFI_SANDBOX === 'true',
            client_id: process.env.EFI_CLIENT_ID_HM,
            client_secret: process.env.EFI_CLIENT_SECRET_HM
        };

        const efipay = new EfiPay(options);

        const normalizeDigits = (v) => String(v || '').replace(/\D/g, '');
        const normalizeEfiPhone = (raw) => {
            let d = normalizeDigits(raw);
            if (!d) return '';
            d = d.replace(/^0+/, '');
            if (d.startsWith('55') && d.length > 11) d = d.slice(2);
            if (d.length > 11) d = d.slice(-11);
            if (!(d.length === 10 || d.length === 11)) return '';
            if (d.startsWith('0')) return '';
            if (d.length === 11 && d[2] !== '9') {
              const d2 = d.slice(0, 2) + d.slice(3);
              if (/^[1-9]{2}[0-9]{8}$/.test(d2)) d = d2;
            }
            if (!/^[1-9]{2}9?[0-9]{8}$/.test(d)) return '';
            return d;
        };
        const isValidCPF = (cpfRaw) => {
            const cpf = normalizeDigits(cpfRaw);
            if (cpf.length !== 11) return false;
            if (/^(\d)\1+$/.test(cpf)) return false;
            const calc = (base, factor) => {
                let sum = 0;
                for (let i = 0; i < base.length; i++) sum += Number(base[i]) * (factor - i);
                const mod = (sum * 10) % 11;
                return mod === 10 ? 0 : mod;
            };
            const d1 = calc(cpf.slice(0, 9), 10);
            const d2 = calc(cpf.slice(0, 10), 11);
            return d1 === Number(cpf[9]) && d2 === Number(cpf[10]);
        };

        const sanitizeItemName = (s) => {
            const raw = String(s || '').replace(/[<>]/g, '').trim();
            return raw ? raw : 'Checkout OPPUS';
        };
        const safeInt = (n) => {
            const v = Number(n);
            if (!Number.isFinite(v)) return null;
            const iv = Math.round(v);
            return Number.isFinite(iv) ? iv : null;
        };

        const qtdSafe = (Number.isFinite(Number(qtdVal)) && Number(qtdVal) > 0) ? Number(qtdVal) : 1;
        const tipoSafe = String(tipoVal || '').trim();
        const validatedValue = safeInt(validatedPriceCents);
        if (validatedValue === null || validatedValue < 100) {
            return res.status(400).json({ error: 'invalid_amount', message: 'Valor inválido para cartão.' });
        }
        validatedValueCents = validatedValue;

        const efiItems = [{
            name: sanitizeItemName(`${qtdSafe} ${tipoSafe}`),
            value: validatedValue,
            amount: 1
        }];

        const cpfDigits = normalizeDigits(customer?.cpf);
        if (!cpfDigits) {
            return res.status(400).json({ error: 'invalid_cpf', message: 'CPF do titular do cartão é obrigatório.' });
        }
        if (!isValidCPF(cpfDigits)) {
            return res.status(400).json({ error: 'invalid_cpf', message: 'CPF do titular do cartão é inválido.' });
        }

        const phoneRaw = customer?.phone_number || customer?.phone || customer?.telefone || customer?.whatsapp || '';
        const phoneDigits = normalizeEfiPhone(phoneRaw);
        const phoneHasInput = normalizeDigits(phoneRaw).length > 0;
        if (phoneHasInput && !phoneDigits) {
            return res.status(400).json({ error: 'invalid_phone', message: 'Telefone inválido. Informe DDD + número (10 ou 11 dígitos).' });
        }
        if (!phoneDigits) {
            return res.status(400).json({ error: 'missing_phone', message: 'Telefone (DDD + número) é obrigatório para pagamento no cartão.' });
        }

        const customerSafe = Object.assign({}, customer || {}, { cpf: cpfDigits }, { phone_number: phoneDigits });

        const params = {};
        const body = {
            payment: {
                credit_card: {
                    installments: Number(installments) || 1,
                    payment_token: payment_token,
                    billing_address: billing_address || {
                        street: 'Av. Paulista',
                        number: 1000,
                        neighborhood: 'Bela Vista',
                        zipcode: '01310100',
                        city: 'São Paulo',
                        state: 'SP'
                    },
                    customer: Object.assign({
                        name: String(customerSafe?.name || '').trim() || 'Cliente',
                        cpf: cpfDigits,
                        email: customerSafe.email || 'cliente@email.com',
                        birth: customerSafe.birth || '1990-01-01'
                    }, (phoneDigits ? { phone_number: phoneDigits } : {}))
                }
            },
            items: efiItems,
            shippings: [
                { name: 'Frete', value: 0 }
            ]
        };

        console.log('💳 Processando pagamento cartão Efí:', { total_cents, installments, has_payment_token: !!payment_token, item_value: validatedValue });

        const charge = await Promise.race([
            efipay.createOneStepCharge(params, body),
            new Promise((_, reject) => setTimeout(() => reject(Object.assign(new Error('payment_timeout'), { code: 'PAYMENT_TIMEOUT' })), 25000))
        ]);

        if (charge && charge.data && charge.data.status !== 'error') {
            // Validação da Resposta (Garantia de que o valor cobrado é o esperado)
            let mismatchStatus = null;
            if (validatedPriceCents !== null && charge.data.total !== validatedPriceCents) {
                console.error(`🚨 CRITICAL: Efí charge total mismatch! Expected: ${validatedPriceCents}, Got: ${charge.data.total}`);
                mismatchStatus = 'divergent_value';
            }

            // Persistência (adaptada do Woovi)
            const addInfoArr = Array.isArray(additionalInfo) ? additionalInfo : [];
            const addInfo = addInfoArr.reduce((acc, item) => {
                const k = String(item?.key || '').trim();
                const v = String(item?.value || '').trim();
                acc[k] = v;
                return acc;
            }, {});

            let utms = {};
            try {
                if (reqUtms && Object.keys(reqUtms).length > 0) {
                    utms = reqUtms;
                    if (!utms.ref) utms.ref = req.get('Referer') || req.headers['referer'] || '';
                } else {
                    const refUrl = req.get('Referer') || req.headers['referer'] || '';
                    utms = { ref: refUrl };
                }
            } catch(_) {
                const refUrl = req.get('Referer') || req.headers['referer'] || '';
                utms = { ref: refUrl };
            }

            const tipo = addInfo['tipo_servico'] || '';
            const qtd = Number(addInfo['quantidade'] || 0) || 0;
            const instauserFromClient = addInfo['instagram_username'] || '';
            const userAgent = req.get('User-Agent') || '';
            const ip = req.realIP || req.ip || req.connection?.remoteAddress || 'unknown';
            const slug = req.session?.linkSlug || '';
            const isPrivate = profile_is_private === true || profile_is_private === 'true' || addInfo['profile_is_private'] === 'true';
            let initialFollowersCount = null;
            let initialFollowersCheckedAt = null;
            try {
                const cat = String(addInfo['categoria_servico'] || '').toLowerCase().trim();
                const uname = String(instauserFromClient || '').trim().toLowerCase().replace(/^@+/, '');
                if (cat === 'seguidores' && uname) {
                    const { getCollection } = require('./mongodbClient');
                    const vu = await getCollection('validated_insta_users');
                    const vUser = await vu.findOne({ username: uname }, { projection: { _id: 0, followersCount: 1, checkedAt: 1, checks: 1 } });
                    const nowMs = Date.now();
                    if (vUser) {
                        let picked = null;
                        if (Array.isArray(vUser.checks) && vUser.checks.length) {
                            const c = vUser.checks[vUser.checks.length - 1];
                            const ts = new Date(c && c.checkedAt ? c.checkedAt : 0).getTime();
                            if (Number.isFinite(ts) && (nowMs - ts) >= 0 && (nowMs - ts) <= (20 * 60 * 1000) && typeof c.followersCount === 'number') {
                                picked = c;
                            }
                        }
                        if (picked) {
                            initialFollowersCount = picked.followersCount;
                            initialFollowersCheckedAt = picked.checkedAt || null;
                        } else if (typeof vUser.followersCount === 'number') {
                            initialFollowersCount = vUser.followersCount;
                            initialFollowersCheckedAt = vUser.checkedAt || null;
                        }
                    }
                }
            } catch (_) {}

            // Geolocalization
            let geolocation = null;
            try {
                const geoPromise = geoLookupIp(ip);
                const timeout = new Promise((resolve) => setTimeout(() => resolve(null), 1200));
                geolocation = await Promise.race([geoPromise, timeout]);
            } catch(_) { geolocation = null; }

            const createdIso = new Date().toISOString();
            
            // Status Efí: 'new', 'waiting', 'paid', 'unpaid', 'refunded', 'contested', 'canceled', 'settled'
            let sysStatus = mismatchStatus || 'pendente';
            if (!mismatchStatus && (charge.data.status === 'paid' || charge.data.status === 'settled')) sysStatus = 'pago';

            const record = {
                nomeUsuario: null,
                telefone: phoneDigits || '',
                instauser: instauserFromClient,
                profilePrivacy: { isPrivate: isPrivate, checkedAt: createdIso },
                isPrivate: isPrivate,
                criado: createdIso,
                identifier: String(charge.data.charge_id),
                correlationID: correlationIDSafe,
                status: sysStatus,
                qtd,
                tipo,
                utms,
                geolocation,
                valueCents: total_cents,
                expectedValueCents: validatedPriceCents,
                customer: customerSafe,
                additionalInfo: addInfoArr,
                tipoServico: tipo,
                quantidade: qtd,
                instagramUsername: instauserFromClient,
                slug,
                userAgent,
                ip,
                createdAt: createdIso,
                paymentMethod: 'credit_card',
                efi: {
                    charge_id: charge.data.charge_id,
                    status: charge.data.status,
                    total: charge.data.total,
                    installments: charge.data.payment?.credit_card?.installments,
                    card_mask: charge.data.payment?.credit_card?.card_mask
                }
            };
            if (initialFollowersCount != null) {
                record.initialFollowersCount = Number(initialFollowersCount);
                record.initialFollowersCheckedAt = initialFollowersCheckedAt || createdIso;
            }

            const col = await getCollection('checkout_orders');
            const insertResult = await col.insertOne(record);
            try { record._id = insertResult?.insertedId; } catch (_) {}
            console.log('🗃️ MongoDB: pedido cartão persistido (Efí charge_id=', charge.data.charge_id, ')');
            Promise.resolve()
              .then(() => queuePaymentRecoveryForNewOrder(col, insertResult && insertResult.insertedId, record))
              .catch(() => {});
            Promise.resolve()
              .then(() => sendOrderCreatedEmail({ record, insertedId: insertResult && insertResult.insertedId }))
              .catch((e) => {
                try { console.warn('⚠️ Falha ao enviar email SMTP (pedido cartão Efí):', e && e.message ? e.message : e); } catch (_) {}
              });
            try {
              if (sysStatus === 'pago') {
                await processOrderFulfillment(record, col, req);
              }
            } catch (_) {}

            return res.json({ success: true, charge: charge.data });
        } else {
            console.error('❌ Efí retornou erro ou status inválido:', charge);
            return res.status(400).json({ error: 'payment_failed', details: charge });
        }

    } catch (error) {
        console.error('❌ Erro pagamento cartão Efí:', error);
        if (String(error?.code || '') === 'PAYMENT_TIMEOUT' || String(error?.message || '') === 'payment_timeout') {
            return res.status(504).json({ error: 'payment_timeout', message: 'Tempo esgotado processando o pagamento. Tente novamente.' });
        }
        const errDesc = error?.error_description;
        const errDescObj = (errDesc && typeof errDesc === 'object') ? errDesc : null;
        const errMsg = String(errDescObj?.message || errDesc || error?.message || error?.error || '').trim();
        const errProp = String(errDescObj?.property || '').trim();
        const code = (typeof error?.code !== 'undefined') ? error.code : undefined;
        const status = (typeof error?.http_status !== 'undefined') ? error.http_status : undefined;
        const codeStr = String(code ?? '').trim();
        if (codeStr === '4600037') {
            const cents = Number.isFinite(Number(validatedValueCents)) ? Number(validatedValueCents) : (Number.isFinite(Number(req.body?.total_cents)) ? Number(req.body.total_cents) : null);
            const valueLabel = Number.isFinite(cents) ? ` (valor: R$ ${(cents / 100).toFixed(2).replace('.', ',')})` : '';
            const envLabel = isSandboxEnv ? 'sandbox' : 'produção';
            return res.status(400).json({
                error: 'efi_operational_limit',
                message: `O valor da cobrança${valueLabel} é superior ao limite operacional da conta Efí (${envLabel}). Aumente o limite no painel da Efí (no mesmo ambiente) ou use PIX.`,
                code,
                status,
                correlationID: correlationIDSafe,
                value_cents: Number.isFinite(cents) ? cents : undefined,
                sandbox: isSandboxEnv
            });
        }
        if (String(error?.error || '') === 'validation_error') {
            if (errProp === '/payment/credit_card/customer/phone_number') {
                const low = String(errMsg || '').toLowerCase();
                const required = /obrigat|required/.test(low);
                return res.status(400).json({ error: required ? 'missing_phone' : 'invalid_phone', message: required ? 'Telefone (DDD + número) é obrigatório para pagamento no cartão.' : 'Telefone inválido. Informe DDD + número (10 ou 11 dígitos).', code, status });
            }
            if (errProp === '/payment/credit_card/customer/cpf') {
                return res.status(400).json({ error: 'invalid_cpf', message: 'CPF do titular do cartão é inválido.', code, status });
            }
            return res.status(400).json({ error: 'validation_error', message: errMsg || 'Erro de validação na Efí.', code, status });
        }
        return res.status(500).json({ error: 'payment_error', message: errMsg || 'Erro ao processar pagamento.', code, status });
    }
});

app.post('/api/pagarme/card-charge', async (req, res) => {
    let correlationIDSafe = '';
    let validatedValueCents = null;
    try {
        const { card_token, card_id, installments, customer, billing_address, total_cents, additionalInfo, profile_is_private, comment, utms: reqUtms } = req.body;
        correlationIDSafe = (function () {
            try {
                const c = String(req.body?.correlationID || '').trim();
                if (c) return c;
            } catch (_) {}
            try {
                const crypto = require('crypto');
                if (crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
            } catch (_) {}
            return `${Date.now()}-${Math.random().toString(16).slice(2)}`;
        })();

        if (!total_cents || total_cents < 100) {
            return res.status(400).json({
                error: 'invalid_amount',
                message: 'Valor mínimo para cartão de crédito é R$ 1,00.'
            });
        }

        const pagarmeKeys = getPagarmeKeys();
        const pagarmeSecret = String(pagarmeKeys.secret || '').trim();
        if (!pagarmeSecret) {
            return res.status(500).json({ error: 'missing_pagarme_secret', message: 'Configuração do Pagar.me ausente (PAGARME_SECRET_KEY).' });
        }

        const addInfoArr = Array.isArray(additionalInfo) ? additionalInfo : [];
        const installmentsMaxEnv = (function () {
            const n = parseInt(String(process.env.PAGARME_INSTALLMENTS_MAX || '12'), 10);
            if (!Number.isFinite(n) || n <= 0) return 12;
            return Math.max(1, Math.min(18, n));
        })();
        const requestedInstallments = (function () {
            const n = parseInt(String(installments || '1'), 10);
            return (Number.isFinite(n) && n > 0) ? n : 1;
        })();
        const installmentsSafe = Math.max(1, Math.min(installmentsMaxEnv, requestedInstallments));
        try {
            for (let i = addInfoArr.length - 1; i >= 0; i--) {
                if (String(addInfoArr[i]?.key || '').trim() === 'installments') addInfoArr.splice(i, 1);
            }
            addInfoArr.push({ key: 'installments', value: String(installmentsSafe) });
        } catch (_) {}
        try {
            const hasTc = addInfoArr.some((it) => String(it?.key || '').trim() === 'tc_code');
            if (!hasTc) {
                const cookieHeader = req.headers['cookie'] || '';
                const m = cookieHeader && cookieHeader.match(/(?:^|;\s*)tc_code=([^;]+)/);
                const tc = m && m[1] ? decodeURIComponent(m[1]) : '';
                if (tc) addInfoArr.push({ key: 'tc_code', value: String(tc) });
            }
        } catch (_) {}
        const addInfoMap = addInfoArr.reduce((acc, item) => {
            const k = String(item?.key || '').trim();
            const v = String(item?.value || '').trim();
            acc[k] = v;
            return acc;
        }, {});

        const tipoVal = addInfoMap['tipo_servico'] || '';
        const qtdVal = Number(addInfoMap['quantidade'] || 0) || 0;

        let verification = await verifyPrice(tipoVal, qtdVal, addInfoArr, Number(total_cents));
        if (!verification.isValid) {
            try {
                const couponCodeRaw = addInfoMap['cupom'] || addInfoMap['coupon'] || '';
                const couponCode = normalizeCouponCode(couponCodeRaw);
                if (couponCode) {
                    const profileKey = normalizeProfileKey(addInfoMap['instagram_username'] || addInfoMap['perfil'] || '');
                    const eligibility = await getCouponEligibility(couponCode, profileKey);
                    if (eligibility && eligibility.ok && eligibility.coupon) {
                        const pct = Number(eligibility.coupon.discountPercentage || 0) || 0;
                        const rate = pct > 0 ? (pct / 100) : 0;
                        if (rate > 0 && Number.isFinite(Number(verification.expectedPrice)) && Number(verification.expectedPrice) > 0) {
                            const expected = Number(verification.expectedPrice);
                            const discountVal = Math.round(expected * rate);
                            const discountedExpected = Math.max(0, expected - discountVal);
                            if (Number(total_cents) === discountedExpected) {
                                verification = { isValid: true, matchedPrice: Number(total_cents), expectedPrice: Number(total_cents), mismatchDetails: null };
                            }
                        }
                    }
                }
            } catch (_) {}
        }
        if (!verification.isValid) {
            return res.status(400).json({ error: 'invalid_amount', message: 'Valor divergente do esperado.' , details: verification.mismatchDetails });
        }
        validatedValueCents = Number(verification.matchedPrice || verification.expectedPrice || 0);
        // Política de limite de parcelas por ticket (valor final)
        const policyCap = (function (v) {
            const n = Number(v) || 0;
            if (n < 1500) return 1;
            if (n < 3000) return 2;
            if (n < 6000) return 6;
            if (n < 10000) return 8;
            if (n < 15000) return 10;
            return 12;
        })(validatedValueCents);
        const effectiveCap = Math.max(1, Math.min(installmentsMaxEnv, policyCap));
        if (installmentsSafe > effectiveCap) {
            return res.status(400).json({ error: 'installments_not_allowed', message: `Parcelamento máximo permitido para este valor é ${effectiveCap}x.` });
        }
        const validatedPriceCents = verification.matchedPrice;
        if (!Number.isFinite(Number(validatedPriceCents)) || Number(validatedPriceCents) < 100) {
            return res.status(400).json({ error: 'invalid_amount', message: 'Valor inválido para cartão.' });
        }
        validatedValueCents = Number(validatedPriceCents);

        const normalizeDigits = (v) => String(v || '').replace(/\D/g, '');
        const isValidCPF = (cpfRaw) => {
            const cpf = normalizeDigits(cpfRaw);
            if (cpf.length !== 11) return false;
            if (/^(\d)\1+$/.test(cpf)) return false;
            const calc = (base, factor) => {
                let sum = 0;
                for (let i = 0; i < base.length; i++) sum += Number(base[i]) * (factor - i);
                const mod = (sum * 10) % 11;
                return mod === 10 ? 0 : mod;
            };
            const d1 = calc(cpf.slice(0, 9), 10);
            const d2 = calc(cpf.slice(0, 10), 11);
            return d1 === Number(cpf[9]) && d2 === Number(cpf[10]);
        };
        const normalizeBrMobilePhone = (raw) => {
            let d = normalizeDigits(raw);
            if (!d) return { areaCode: '', number: '' };
            d = d.replace(/^0+/, '');
            if (d.startsWith('55') && d.length > 11) d = d.slice(2);
            if (d.length > 11) d = d.slice(-11);
            if (!(d.length === 10 || d.length === 11)) return { areaCode: '', number: '' };
            if (d.startsWith('0')) return { areaCode: '', number: '' };
            if (d.length === 11 && d[2] !== '9') {
                const d2 = d.slice(0, 2) + d.slice(3);
                if (/^[1-9]{2}[0-9]{8}$/.test(d2)) d = d2;
            }
            const areaCode = d.slice(0, 2);
            const number = d.slice(2);
            if (!/^[1-9]{2}$/.test(areaCode) || !/^\d{8,9}$/.test(number)) return { areaCode: '', number: '' };
            return { areaCode, number };
        };

        const cpfDigits = normalizeDigits(customer?.cpf);
        if (!cpfDigits) return res.status(400).json({ error: 'invalid_cpf', message: 'CPF do titular do cartão é obrigatório.' });
        if (!isValidCPF(cpfDigits)) return res.status(400).json({ error: 'invalid_cpf', message: 'CPF do titular do cartão é inválido.' });

        const phoneRaw = customer?.phone_number || customer?.phone || customer?.telefone || customer?.whatsapp || '';
        const phoneDigits = normalizeDigits(phoneRaw);
        const phoneHasInput = phoneDigits.length > 0;
        const phone = normalizeBrMobilePhone(phoneRaw);
        if (phoneHasInput && (!phone.areaCode || !phone.number)) {
            return res.status(400).json({ error: 'invalid_phone', message: 'Telefone inválido. Informe DDD + número (10 ou 11 dígitos).' });
        }
        if (!phone.areaCode || !phone.number) {
            return res.status(400).json({ error: 'missing_phone', message: 'Telefone (DDD + número) é obrigatório para pagamento no cartão.' });
        }

        const customerName = String(customer?.name || '').trim() || 'Cliente';
        const customerEmail = String(customer?.email || '').trim() || 'cliente@email.com';

        const billingAddress = (function () {
            const b = billing_address && typeof billing_address === 'object' ? billing_address : null;
            const line1 = String(b?.line_1 || b?.street || '').trim() || 'Av. Paulista, 1000';
            const zip = normalizeDigits(b?.zip_code || b?.zipcode || '') || '01310100';
            const city = String(b?.city || '').trim() || 'São Paulo';
            const state = String(b?.state || '').trim() || 'SP';
            const country = String(b?.country || '').trim() || 'BR';
            const out = { line_1: line1, zip_code: zip, city, state, country };
            if (b?.line_2) out.line_2 = String(b.line_2 || '').trim();
            if (b?.neighborhood) out.neighborhood = String(b.neighborhood || '').trim();
            return out;
        })();

        const token = String(card_token || '').trim();
        const cardId = String(card_id || '').trim();
        if (!token && !cardId) {
            return res.status(400).json({ error: 'missing_card_token', message: 'Token do cartão é obrigatório.' });
        }

        let utms = {};
        try {
            if (reqUtms && Object.keys(reqUtms).length > 0) {
                utms = reqUtms;
                if (!utms.ref) utms.ref = req.get('Referer') || req.headers['referer'] || '';
            } else {
                const refUrl = req.get('Referer') || req.headers['referer'] || '';
                const u = new URL(refUrl);
                const p = u.searchParams;
                utms = {
                    source: p.get('utm_source') || '',
                    medium: p.get('utm_medium') || '',
                    campaign: p.get('utm_campaign') || '',
                    term: p.get('utm_term') || '',
                    content: p.get('utm_content') || '',
                    gclid: p.get('gclid') || '',
                    fbclid: p.get('fbclid') || '',
                    ref: refUrl
                };
            }
        } catch (_) {
            const refUrl = req.get('Referer') || req.headers['referer'] || '';
            utms = { ref: refUrl };
        }

        const tipo = addInfoMap['tipo_servico'] || '';
        const qtd = Number(addInfoMap['quantidade'] || 0) || 0;
        const instauserFromClient = addInfoMap['instagram_username'] || '';
        const userAgent = req.get('User-Agent') || '';
        const ip = req.realIP || req.ip || req.connection?.remoteAddress || 'unknown';
        const slug = req.session?.linkSlug || '';
        const isPrivate = profile_is_private === true || profile_is_private === 'true' || addInfoMap['profile_is_private'] === 'true';
        const createdIso = new Date().toISOString();

        let geolocation = null;
        try {
            const geoPromise = geoLookupIp(ip);
            const timeout = new Promise((resolve) => setTimeout(() => resolve(null), 1200));
            geolocation = await Promise.race([geoPromise, timeout]);
        } catch (_) { geolocation = null; }

        const itemCode = (function () {
            const raw = `${tipo || 'item'}_${qtd || 1}`;
            const cleaned = raw
                .toLowerCase()
                .replace(/[^a-z0-9_-]+/g, '_')
                .replace(/_+/g, '_')
                .replace(/^_+|_+$/g, '');
            const fallback = `item_${qtd || 1}`;
            const out = (cleaned || fallback).slice(0, 52);
            return out;
        })();

        const pagarmeMetadata = (function () {
            const out = {};
            const normKey = (k) => String(k || '').trim().replace(/[^a-zA-Z0-9_]+/g, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '').slice(0, 60);
            const normVal = (v, maxLen) => {
                const s = String(v === undefined || v === null ? '' : v).trim();
                if (!s) return '';
                return (typeof maxLen === 'number' && maxLen > 0 && s.length > maxLen) ? s.slice(0, maxLen) : s;
            };
            const set = (k, v, maxLen) => {
                const key = normKey(k);
                const val = normVal(v, maxLen);
                if (!key || !val) return;
                out[key] = val;
            };

            const allowedKeys = new Set([
                'correlationid',
                'tipo_servico',
                'categoria_servico',
                'quantidade',
                'pacote',
                'instagram_username',
                'phone',
                'order_bumps_total',
                'order_bumps',
                'cupom',
                'tc_code',
                'sck',
                'utm_source',
                'utm_medium',
                'utm_campaign',
                'utm_term',
                'utm_content',
                'gclid',
                'fbclid'
            ]);

            set('correlationID', correlationIDSafe, 120);
            set('tipo_servico', tipo, 80);
            set('categoria_servico', addInfoMap['categoria_servico'] || '', 80);
            set('quantidade', qtd, 40);
            set('pacote', addInfoMap['pacote'] || '', 200);
            set('instagram_username', instauserFromClient, 80);
            set('phone', addInfoMap['phone'] || `${phone.areaCode}${phone.number}`, 40);

            try {
                const keys = Object.keys(addInfoMap || {});
                for (let i = 0; i < keys.length; i++) {
                    const rawK = keys[i];
                    if (!rawK) continue;
                    const k = normKey(rawK);
                    const kLower = String(k || '').toLowerCase();
                    if (!kLower) continue;
                    if (kLower === 'slug' || kLower === 'ref' || kLower === 'profile_is_private') continue;
                    if (!allowedKeys.has(kLower) && !kLower.startsWith('orderbump_post_')) continue;
                    set(k, addInfoMap[rawK], 220);
                    if (Object.keys(out).length >= 45) break;
                }
            } catch (_) {}

            try {
                if (utms && typeof utms === 'object') {
                    set('utm_source', utms.source || '', 120);
                    set('utm_medium', utms.medium || '', 120);
                    set('utm_campaign', utms.campaign || '', 120);
                    set('utm_term', utms.term || '', 120);
                    set('utm_content', utms.content || '', 120);
                    set('gclid', utms.gclid || '', 160);
                    set('fbclid', utms.fbclid || '', 160);
                }
            } catch (_) {}

            return out;
        })();

        const orderBody = {
            code: correlationIDSafe,
            items: [
                {
                    amount: Number(validatedValueCents),
                    code: itemCode,
                    description: String(addInfoMap['pacote'] || `${qtd || 1} ${tipo || 'serviço'}`).trim() || 'Checkout OPPUS',
                    quantity: 1
                }
            ],
            customer: {
                name: customerName,
                email: customerEmail,
                document_type: 'CPF',
                document: cpfDigits,
                type: 'Individual',
                address: billingAddress,
                phones: {
                    mobile_phone: {
                        country_code: '55',
                        area_code: phone.areaCode,
                        number: phone.number
                    }
                }
            },
            payments: [
                {
                    amount: Number(validatedValueCents),
                    payment_method: 'credit_card',
                    credit_card: Object.assign(
                        {
                            installments: installmentsSafe,
                            statement_descriptor: 'AGENCIA OPPUS',
                            operation_type: 'auth_and_capture',
                            card: { billing_address: billingAddress }
                        },
                        token ? { card_token: token } : {},
                        cardId ? { card_id: cardId } : {}
                    )
                }
            ],
            metadata: pagarmeMetadata,
            closed: true,
            ip
        };

        const auth = Buffer.from(`${pagarmeSecret}:`).toString('base64');
        const resp = await axios.post('https://api.pagar.me/core/v5/orders', orderBody, {
            headers: {
                'Accept': 'application/json',
                'Content-Type': 'application/json',
                'Authorization': `Basic ${auth}`
            },
            timeout: 45000
        });

        const order = resp && resp.data ? resp.data : null;
        if (!order) return res.status(500).json({ error: 'pagarme_empty_response', message: 'Resposta vazia do Pagar.me.' });

        const orderStatus = String(order.status || '').toLowerCase();
        const charge = Array.isArray(order.charges) ? order.charges[0] : null;
        const chargeStatus = String(charge?.status || '').toLowerCase();
        const lastTxStatus = String(charge?.last_transaction?.status || '').toLowerCase();
        const lastTx = (charge && charge.last_transaction && typeof charge.last_transaction === 'object') ? charge.last_transaction : {};

        const normalizedTxStatus = (function () {
            const s = String(lastTxStatus || chargeStatus || orderStatus || '').toLowerCase().trim();
            if (!s) return 'unknown';
            if (s === 'paid' || s === 'captured') return 'paid';
            if (s === 'failed' || s === 'refused' || s === 'canceled' || s === 'cancelled' || s === 'voided') return 'failed';
            if (s === 'authorized' || s === 'pending' || s === 'processing' || s === 'analyzing' || s === 'analysis') return 'pending';
            return s;
        })();

        let sysStatus = 'pendente';
        if (normalizedTxStatus === 'paid') sysStatus = 'pago';
        if (normalizedTxStatus === 'failed') sysStatus = 'falha';

        const pagarmeFailure = (function () {
            if (normalizedTxStatus !== 'failed') return null;
            const out = {};
            const add = (k, v, maxLen) => {
                if (v === undefined || v === null) return;
                const s = String(v).trim();
                if (!s) return;
                out[k] = (typeof maxLen === 'number' && maxLen > 0 && s.length > maxLen) ? s.slice(0, maxLen) : s;
            };
            add('order_status', order?.status, 64);
            add('charge_status', charge?.status, 64);
            add('transaction_status', lastTx?.status, 64);
            add('acquirer_name', lastTx?.acquirer_name, 80);
            add('acquirer_message', lastTx?.acquirer_message, 300);
            add('acquirer_return_code', lastTx?.acquirer_return_code, 80);
            add('gateway_response_code', lastTx?.gateway_response_code, 80);
            add('gateway_message', lastTx?.gateway_response?.message, 300);
            add('gateway_code', lastTx?.gateway_response?.code, 80);
            add('gateway_errors', Array.isArray(lastTx?.gateway_response?.errors) ? JSON.stringify(lastTx.gateway_response.errors) : '', 1200);
            add('antifraud_status', lastTx?.antifraud_response?.status || lastTx?.antifraud_response?.result, 80);
            add('antifraud_score', lastTx?.antifraud_response?.score, 80);
            add('antifraud_provider', lastTx?.antifraud_response?.provider, 80);
            add('refusal_reason', lastTx?.refusal_reason, 120);
            return Object.keys(out).length ? out : null;
        })();

        let initialFollowersCount = null;
        let initialFollowersCheckedAt = null;
        try {
            const cat = String((addInfoArr.find(it => it && it.key === 'categoria_servico')?.value) || '').toLowerCase().trim();
            const uname = String(instauserFromClient || '').trim().toLowerCase().replace(/^@+/, '');
            if (cat === 'seguidores' && uname) {
                const { getCollection } = require('./mongodbClient');
                const vu = await getCollection('validated_insta_users');
                const vUser = await vu.findOne({ username: uname }, { projection: { _id: 0, followersCount: 1, checkedAt: 1, checks: 1 } });
                const nowMs = Date.now();
                if (vUser) {
                    let picked = null;
                    if (Array.isArray(vUser.checks) && vUser.checks.length) {
                        const c = vUser.checks[vUser.checks.length - 1];
                        const ts = new Date(c && c.checkedAt ? c.checkedAt : 0).getTime();
                        if (Number.isFinite(ts) && (nowMs - ts) >= 0 && (nowMs - ts) <= (20 * 60 * 1000) && typeof c.followersCount === 'number') {
                            picked = c;
                        }
                    }
                    if (picked) {
                        initialFollowersCount = picked.followersCount;
                        initialFollowersCheckedAt = picked.checkedAt || null;
                    } else if (typeof vUser.followersCount === 'number') {
                        initialFollowersCount = vUser.followersCount;
                        initialFollowersCheckedAt = vUser.checkedAt || null;
                    }
                }
            }
        } catch (_) {}

        const record = {
            nomeUsuario: null,
            telefone: `${phone.areaCode}${phone.number}`,
            instauser: instauserFromClient,
            profilePrivacy: { isPrivate: isPrivate, checkedAt: createdIso },
            isPrivate: isPrivate,
            criado: createdIso,
            identifier: String(order.id || charge?.id || ''),
            correlationID: correlationIDSafe,
            status: sysStatus,
            qtd,
            tipo,
            utms,
            geolocation,
            valueCents: total_cents,
            expectedValueCents: validatedValueCents,
            customer: Object.assign({}, customer || {}, { cpf: cpfDigits }, { phone_number: `${phone.areaCode}${phone.number}` }),
            additionalInfo: addInfoArr,
            tipoServico: tipo,
            quantidade: qtd,
            instagramUsername: instauserFromClient,
            slug,
            userAgent,
            ip,
            createdAt: createdIso,
            paymentMethod: 'credit_card',
            pagarme: {
                environment: pagarmeKeys.useTest ? 'test' : 'live',
                order_id: order.id,
                order_status: order.status,
                charge_id: charge?.id,
                charge_status: charge?.status,
                transaction_id: charge?.last_transaction?.id,
                transaction_status: charge?.last_transaction?.status,
                installments: charge?.last_transaction?.installments,
                failure: pagarmeFailure
            },
            paidAt: sysStatus === 'pago' ? (lastTx?.paid_at || lastTx?.created_at || createdIso) : null
        };
        if (initialFollowersCount != null) {
            record.initialFollowersCount = Number(initialFollowersCount);
            record.initialFollowersCheckedAt = initialFollowersCheckedAt || createdIso;
        }

        const col = await getCollection('checkout_orders');
        const insertResult = await col.insertOne(record);
        try { record._id = insertResult?.insertedId; } catch (_) {}
        Promise.resolve()
            .then(() => queuePaymentRecoveryForNewOrder(col, insertResult && insertResult.insertedId, record))
            .catch(() => {});
        Promise.resolve()
            .then(() => sendOrderCreatedEmail({ record, insertedId: insertResult && insertResult.insertedId }))
            .catch((e) => {
                try { console.warn('⚠️ Falha ao enviar email SMTP (pedido cartão Pagar.me):', e && e.message ? e.message : e); } catch (_) {}
            });

        try {
            if (sysStatus === 'pago' && !pagarmeKeys.useTest) {
                await processOrderFulfillment(record, col, req);
            }
        } catch (_) {}

        const responsePayload = {
            success: sysStatus === 'pago',
            paid: sysStatus === 'pago',
            correlationID: correlationIDSafe,
            identifier: String(record.identifier || ''),
            pagarme: {
                environment: pagarmeKeys.useTest ? 'test' : 'live',
                order_id: order?.id,
                order_status: order?.status,
                charge_id: charge?.id,
                charge_status: charge?.status,
                transaction_id: charge?.last_transaction?.id,
                transaction_status: charge?.last_transaction?.status
            },
            pagarme_failure: pagarmeFailure,
            order
        };

        if (sysStatus === 'pago') return res.json(responsePayload);

        if (normalizedTxStatus === 'pending') {
            return res.status(202).json(Object.assign({}, responsePayload, {
                error: 'payment_pending',
                message: `Pagamento em análise no Pagar.me (${String(charge?.last_transaction?.status || charge?.status || order?.status || '').trim() || 'pendente'}).`
            }));
        }

        return res.status(402).json(Object.assign({}, responsePayload, {
            error: 'payment_failed',
            message: `Pagamento não aprovado no Pagar.me (${String(charge?.last_transaction?.status || charge?.status || order?.status || '').trim() || 'falhou'}).`
        }));
    } catch (error) {
        const status = error?.response?.status;
        const data = error?.response?.data;
        const msg = String(
            (Array.isArray(data?.errors) && data.errors[0] && data.errors[0].message ? data.errors[0].message : '') ||
            data?.message ||
            data?.error ||
            error?.message ||
            ''
        ).trim();
        console.error('❌ Erro pagamento cartão Pagar.me:', { status, msg });
        if (status && status >= 400 && status < 500) {
            return res.status(status).json({ error: 'pagarme_request_error', message: msg || 'Erro na requisição ao Pagar.me.', details: data, correlationID: correlationIDSafe });
        }
        return res.status(500).json({ error: 'payment_error', message: msg || 'Erro ao processar pagamento.', details: data, correlationID: correlationIDSafe });
    }
});

app.post('/api/stripe/create-intent', async (req, res) => {
  let correlationIDSafe = '';
  let validatedValueCents = null;
  try {
    const { installments, customer, total_cents, additionalInfo, profile_is_private, utms: reqUtms } = req.body;
    correlationIDSafe = (function () {
      try {
        const c = String(req.body?.correlationID || '').trim();
        if (c) return c;
      } catch (_) {}
      try {
        const crypto = require('crypto');
        if (crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
      } catch (_) {}
      return `${Date.now()}-${Math.random().toString(16).slice(2)}`;
    })();

    const stripeKeys = getStripeKeys();
    const stripeSecret = String(stripeKeys.secret || '').trim();
    if (!stripeSecret) {
      return res.status(500).json({ error: 'missing_stripe_secret', message: 'Configuração da Stripe ausente (STRIPE_SECRET_KEY).' });
    }

    if (!total_cents || Number(total_cents) < 100) {
      return res.status(400).json({ error: 'invalid_amount', message: 'Valor mínimo para cartão de crédito é R$ 1,00.' });
    }

    const addInfoArr = Array.isArray(additionalInfo) ? additionalInfo : [];
    const addInfoMap = addInfoArr.reduce((acc, item) => {
      const k = String(item?.key || '').trim();
      const v = String(item?.value || '').trim();
      acc[k] = v;
      return acc;
    }, {});

    const tipoVal = addInfoMap['tipo_servico'] || '';
    const qtdVal = Number(addInfoMap['quantidade'] || 0) || 0;

    let verification = await verifyPrice(tipoVal, qtdVal, addInfoArr, Number(total_cents));
    if (!verification.isValid) {
      try {
        const couponCodeRaw = addInfoMap['cupom'] || addInfoMap['coupon'] || '';
        const couponCode = normalizeCouponCode(couponCodeRaw);
        if (couponCode) {
          const profileKey = normalizeProfileKey(addInfoMap['instagram_username'] || addInfoMap['perfil'] || '');
          const eligibility = await getCouponEligibility(couponCode, profileKey);
          if (eligibility && eligibility.ok && eligibility.coupon) {
            const pct = Number(eligibility.coupon.discountPercentage || 0) || 0;
            const rate = pct > 0 ? (pct / 100) : 0;
            if (rate > 0 && Number.isFinite(Number(verification.expectedPrice)) && Number(verification.expectedPrice) > 0) {
              const expected = Number(verification.expectedPrice);
              const discountVal = Math.round(expected * rate);
              const discountedExpected = Math.max(0, expected - discountVal);
              if (Number(total_cents) === discountedExpected) {
                verification = { isValid: true, matchedPrice: Number(total_cents), expectedPrice: Number(total_cents), mismatchDetails: null };
              }
            }
          }
        }
      } catch (_) {}
    }
    if (!verification.isValid) {
      return res.status(400).json({ error: 'invalid_amount', message: 'Valor divergente do esperado.', details: verification.mismatchDetails });
    }
    const validatedPriceCents = Number(verification.matchedPrice || verification.expectedPrice || 0);
    if (!Number.isFinite(validatedPriceCents) || validatedPriceCents < 100) {
      return res.status(400).json({ error: 'invalid_amount', message: 'Valor inválido para cartão.' });
    }
    validatedValueCents = validatedPriceCents;

    const normalizeDigits = (v) => String(v || '').replace(/\D/g, '');
    const isValidCPF = (cpfRaw) => {
      const cpf = normalizeDigits(cpfRaw);
      if (cpf.length !== 11) return false;
      if (/^(\d)\1+$/.test(cpf)) return false;
      const calc = (base, factor) => {
        let sum = 0;
        for (let i = 0; i < base.length; i++) sum += Number(base[i]) * (factor - i);
        const mod = (sum * 10) % 11;
        return mod === 10 ? 0 : mod;
      };
      const d1 = calc(cpf.slice(0, 9), 10);
      const d2 = calc(cpf.slice(0, 10), 11);
      return d1 === Number(cpf[9]) && d2 === Number(cpf[10]);
    };
    const normalizeBrMobile = (raw) => {
      let d = normalizeDigits(raw);
      if (!d) return '';
      d = d.replace(/^0+/, '');
      if (d.startsWith('55') && d.length > 11) d = d.slice(2);
      if (d.length > 11) d = d.slice(-11);
      if (!(d.length === 10 || d.length === 11)) return '';
      if (d.startsWith('0')) return '';
      if (d.length === 11 && d[2] !== '9') {
        const d2 = d.slice(0, 2) + d.slice(3);
        if (/^[1-9]{2}[0-9]{8}$/.test(d2)) d = d2;
      }
      if (!/^[1-9]{2}\d{8,9}$/.test(d)) return '';
      return d;
    };

    const cpfDigits = normalizeDigits(customer?.cpf);
    if (cpfDigits && !isValidCPF(cpfDigits)) return res.status(400).json({ error: 'invalid_cpf', message: 'CPF inválido.' });

    const phoneRaw = customer?.phone_number || customer?.phone || customer?.telefone || customer?.whatsapp || '';
    const phoneDigits = normalizeBrMobile(phoneRaw);
    if (!phoneDigits) return res.status(400).json({ error: 'missing_phone', message: 'Telefone (DDD + número) é obrigatório para pagamento no cartão.' });

    const emailSafe = (function () {
      const raw = String(customer?.email || '').trim();
      if (!raw) return '';
      if (raw.length > 180) return '';
      const at = raw.indexOf('@');
      if (at <= 0 || at >= raw.length - 3) return '';
      if (raw.indexOf('.', at) === -1) return '';
      return raw;
    })();

    let utms = {};
    try {
      if (reqUtms && Object.keys(reqUtms).length > 0) {
        utms = reqUtms;
        if (!utms.ref) utms.ref = req.get('Referer') || req.headers['referer'] || '';
      } else {
        const refUrl = req.get('Referer') || req.headers['referer'] || '';
        utms = { ref: refUrl };
      }
    } catch (_) {
      const refUrl = req.get('Referer') || req.headers['referer'] || '';
      utms = { ref: refUrl };
    }

    const tipo = addInfoMap['tipo_servico'] || '';
    const qtd = Number(addInfoMap['quantidade'] || 0) || 0;
    const instauserFromClient = addInfoMap['instagram_username'] || '';
    const userAgent = req.get('User-Agent') || '';
    const ip = req.realIP || req.ip || req.connection?.remoteAddress || 'unknown';
    const slug = req.session?.linkSlug || '';
    const isPrivate = profile_is_private === true || profile_is_private === 'true' || addInfoMap['profile_is_private'] === 'true';
    const createdIso = new Date().toISOString();

    let geolocation = null;
    try {
      const geoPromise = geoLookupIp(ip);
      const timeout = new Promise((resolve) => setTimeout(() => resolve(null), 1200));
      geolocation = await Promise.race([geoPromise, timeout]);
    } catch (_) { geolocation = null; }

    const installmentsSafe = (function () {
      const n = parseInt(String(installments || '1'), 10);
      return (Number.isFinite(n) && n > 0) ? n : 1;
    })();
    try {
      for (let i = addInfoArr.length - 1; i >= 0; i--) {
        if (String(addInfoArr[i]?.key || '').trim() === 'installments') addInfoArr.splice(i, 1);
      }
      addInfoArr.push({ key: 'installments', value: String(installmentsSafe) });
    } catch (_) {}

    const stripeMetadata = (function () {
      const out = {};
      const normKey = (k) => String(k || '').trim().replace(/[^a-zA-Z0-9_]+/g, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '').slice(0, 40);
      const normVal = (v) => {
        const s = String(v === undefined || v === null ? '' : v).trim();
        if (!s) return '';
        return s.length > 450 ? s.slice(0, 450) : s;
      };
      const set = (k, v) => {
        const kk = normKey(k);
        const vv = normVal(v);
        if (!kk || !vv) return;
        out[kk] = vv;
      };
      set('correlationID', correlationIDSafe);
      set('tipo_servico', tipo);
      set('categoria_servico', addInfoMap['categoria_servico'] || '');
      set('quantidade', qtd);
      set('instagram_username', instauserFromClient);
      set('phone', phoneDigits);
      set('slug', slug);
      set('tc_code', addInfoMap['tc_code'] || '');
      try {
        if (utms && typeof utms === 'object') {
          set('utm_source', utms.source || '');
          set('utm_medium', utms.medium || '');
          set('utm_campaign', utms.campaign || '');
          set('utm_term', utms.term || '');
          set('utm_content', utms.content || '');
          set('gclid', utms.gclid || '');
          set('fbclid', utms.fbclid || '');
        }
      } catch (_) {}
      try {
        const maxKeys = 45;
        const items = Array.isArray(addInfoArr) ? addInfoArr : [];
        for (let i = 0; i < items.length; i++) {
          if (Object.keys(out).length >= maxKeys) break;
          const it = items[i];
          const kRaw = String(it?.key || '').trim();
          const vRaw = String(it?.value || '').trim();
          if (!kRaw || !vRaw) continue;
          set(`ai_${kRaw}`, vRaw);
        }
      } catch (_) {}
      return out;
    })();

    const stripeCreatePaymentIntent = async (opts) => {
      const sp = new URLSearchParams();
      sp.append('amount', String(opts.amount));
      sp.append('currency', String(opts.currency));
      sp.append('payment_method_types[]', 'card');
      if (opts.description) sp.append('description', String(opts.description));
      if (opts.metadata && typeof opts.metadata === 'object') {
        const keys = Object.keys(opts.metadata);
        for (let i = 0; i < keys.length; i++) {
          const k = keys[i];
          const v = opts.metadata[k];
          if (v === undefined || v === null) continue;
          const s = String(v).trim();
          if (!s) continue;
          sp.append(`metadata[${k}]`, s);
        }
      }
      const resp = await axios.post('https://api.stripe.com/v1/payment_intents', sp.toString(), {
        headers: {
          'Authorization': `Bearer ${stripeSecret}`,
          'Content-Type': 'application/x-www-form-urlencoded',
          'Idempotency-Key': correlationIDSafe
        },
        timeout: 45000
      });
      return resp && resp.data ? resp.data : null;
    };

    const description = String(addInfoMap['pacote'] || `${qtd || 1} ${tipo || 'serviço'}`).trim().slice(0, 500);
    const pi = await stripeCreatePaymentIntent({
      amount: Number(validatedValueCents),
      currency: 'brl',
      description,
      metadata: stripeMetadata
    });
    if (!pi || !pi.id || !pi.client_secret) {
      return res.status(502).json({ error: 'stripe_empty_response', message: 'Resposta vazia da Stripe.' });
    }

    let initialFollowersCount = null;
    let initialFollowersCheckedAt = null;
    try {
      const cat = String((addInfoArr.find(it => it && it.key === 'categoria_servico')?.value) || '').toLowerCase().trim();
      const uname = String(instauserFromClient || '').trim().toLowerCase().replace(/^@+/, '');
      if (cat === 'seguidores' && uname) {
        const { getCollection } = require('./mongodbClient');
        const vu = await getCollection('validated_insta_users');
        const vUser = await vu.findOne({ username: uname }, { projection: { _id: 0, followersCount: 1, checkedAt: 1, checks: 1 } });
        const nowMs = Date.now();
        if (vUser) {
          let picked = null;
          if (Array.isArray(vUser.checks) && vUser.checks.length) {
            const c = vUser.checks[vUser.checks.length - 1];
            const ts = new Date(c && c.checkedAt ? c.checkedAt : 0).getTime();
            if (Number.isFinite(ts) && (nowMs - ts) >= 0 && (nowMs - ts) <= (20 * 60 * 1000) && typeof c.followersCount === 'number') {
              picked = c;
            }
          }
          if (picked) {
            initialFollowersCount = picked.followersCount;
            initialFollowersCheckedAt = picked.checkedAt || null;
          } else if (typeof vUser.followersCount === 'number') {
            initialFollowersCount = vUser.followersCount;
            initialFollowersCheckedAt = vUser.checkedAt || null;
          }
        }
      }
    } catch (_) {}

    const record = {
      nomeUsuario: null,
      telefone: phoneDigits || '',
      instauser: instauserFromClient,
      profilePrivacy: { isPrivate: isPrivate, checkedAt: createdIso },
      isPrivate: isPrivate,
      criado: createdIso,
      identifier: String(pi.id),
      correlationID: correlationIDSafe,
      status: 'pendente',
      qtd,
      tipo,
      utms,
      geolocation,
      valueCents: Number(total_cents),
      expectedValueCents: Number(validatedValueCents),
      customer: Object.assign({}, customer || {}, (cpfDigits ? { cpf: cpfDigits } : {}), (emailSafe ? { email: emailSafe } : {}), { phone_number: phoneDigits }),
      additionalInfo: addInfoArr,
      tipoServico: tipo,
      quantidade: qtd,
      instagramUsername: instauserFromClient,
      slug,
      userAgent,
      ip,
      createdAt: createdIso,
      paymentMethod: 'credit_card',
      stripe: {
        environment: stripeKeys.useTest ? 'test' : 'live',
        payment_intent_id: pi.id,
        status: String(pi.status || ''),
        amount: Number(pi.amount || validatedValueCents),
        currency: String(pi.currency || 'brl')
      }
    };
    if (initialFollowersCount != null) {
      record.initialFollowersCount = Number(initialFollowersCount);
      record.initialFollowersCheckedAt = initialFollowersCheckedAt || createdIso;
    }

    const col = await getCollection('checkout_orders');
    const insertResult = await col.insertOne(record);
    try { record._id = insertResult?.insertedId; } catch (_) {}
    Promise.resolve()
      .then(() => queuePaymentRecoveryForNewOrder(col, insertResult && insertResult.insertedId, record))
      .catch(() => {});
    Promise.resolve()
      .then(() => sendOrderCreatedEmail({ record, insertedId: insertResult && insertResult.insertedId }))
      .catch(() => {});

    return res.json({
      ok: true,
      correlationID: correlationIDSafe,
      identifier: String(pi.id),
      paymentIntentId: String(pi.id),
      clientSecret: String(pi.client_secret)
    });
  } catch (error) {
    const status = error?.response?.status;
    const data = error?.response?.data;
    const msg = String(
      data?.error?.message ||
      (Array.isArray(data?.error?.errors) && data.error.errors[0] && data.error.errors[0].reason ? data.error.errors[0].reason : '') ||
      data?.message ||
      data?.error ||
      error?.message ||
      ''
    ).trim();
    if (status && status >= 400 && status < 500) {
      return res.status(status).json({ error: 'stripe_request_error', message: msg || 'Erro na requisição à Stripe.', details: data, correlationID: correlationIDSafe });
    }
    return res.status(500).json({ error: 'stripe_error', message: msg || 'Erro ao criar pagamento na Stripe.', details: data, correlationID: correlationIDSafe });
  }
});

app.post('/api/stripe/confirm-intent', async (req, res) => {
  try {
    const stripeKeys = getStripeKeys();
    const stripeSecret = String(stripeKeys.secret || '').trim();
    if (!stripeSecret) return res.status(500).json({ error: 'missing_stripe_secret', message: 'Configuração da Stripe ausente (STRIPE_SECRET_KEY).' });

    const paymentIntentId = String(req.body?.payment_intent_id || req.body?.paymentIntentId || req.body?.id || '').trim();
    const identifier = String(req.body?.identifier || '').trim();
    const correlationID = String(req.body?.correlationID || '').trim();
    const pickId = paymentIntentId || identifier;
    if (!pickId) return res.status(400).json({ error: 'missing_payment_intent', message: 'payment_intent_id é obrigatório.' });

    const piResp = await axios.get(`https://api.stripe.com/v1/payment_intents/${encodeURIComponent(pickId)}`, {
      headers: { 'Authorization': `Bearer ${stripeSecret}` },
      timeout: 45000
    });
    const pi = piResp && piResp.data ? piResp.data : null;
    if (!pi || !pi.id) return res.status(502).json({ error: 'stripe_empty_response', message: 'Resposta vazia da Stripe.' });

    const col = await getCollection('checkout_orders');
    const conds = [];
    if (identifier) conds.push({ identifier });
    if (paymentIntentId) conds.push({ 'stripe.payment_intent_id': paymentIntentId });
    conds.push({ identifier: pi.id });
    conds.push({ 'stripe.payment_intent_id': pi.id });
    if (correlationID) conds.push({ correlationID });
    const record = await col.findOne({ $or: conds });
    if (!record) return res.status(404).json({ error: 'order_not_found', message: 'Pedido não encontrado para este pagamento.' });

    const expected = Number(record.expectedValueCents || record.valueCents || 0);
    const piAmount = Number(pi.amount || 0);
    if (Number.isFinite(expected) && expected > 0 && Number.isFinite(piAmount) && piAmount > 0 && expected !== piAmount) {
      await col.updateOne({ _id: record._id }, { $set: { status: 'falha', stripe: Object.assign({}, record.stripe || {}, { status: String(pi.status || ''), amount: piAmount, mismatch: true }) } });
      return res.status(409).json({ error: 'amount_mismatch', message: 'Valor do pagamento divergente do pedido.' });
    }

    const piStatus = String(pi.status || '').toLowerCase();
    const isPaid = piStatus === 'succeeded';
    const sysStatus = isPaid ? 'pago' : ((piStatus === 'processing' || piStatus === 'requires_action' || piStatus === 'requires_payment_method' || piStatus === 'requires_confirmation') ? 'pendente' : 'falha');

    const update = {
      status: sysStatus,
      paidAt: isPaid ? new Date().toISOString() : (record.paidAt || null),
      stripe: Object.assign({}, record.stripe || {}, {
        environment: stripeKeys.useTest ? 'test' : 'live',
        payment_intent_id: pi.id,
        status: String(pi.status || ''),
        amount: Number(pi.amount || record?.stripe?.amount || expected || 0),
        currency: String(pi.currency || record?.stripe?.currency || 'brl')
      })
    };
    await col.updateOne({ _id: record._id }, { $set: update });

    if (isPaid) {
      try {
        const fresh = Object.assign({}, record, update);
        await processOrderFulfillment(fresh, col, req);
      } catch (_) {}
    }

    return res.json({
      ok: true,
      paid: isPaid,
      status: sysStatus,
      identifier: String(record.identifier || pi.id),
      correlationID: String(record.correlationID || correlationID || '')
    });
  } catch (error) {
    const status = error?.response?.status;
    const data = error?.response?.data;
    const msg = String(
      data?.error?.message ||
      data?.message ||
      data?.error ||
      error?.message ||
      ''
    ).trim();
    if (status && status >= 400 && status < 500) return res.status(status).json({ error: 'stripe_request_error', message: msg || 'Erro na requisição à Stripe.', details: data });
    return res.status(500).json({ error: 'stripe_error', message: msg || 'Erro ao confirmar pagamento na Stripe.', details: data });
  }
});

