// API para verificar privacidade do perfil (sem bloqueio de uso)
app.post("/api/check-privacy", async (req, res) => {
    const { username } = req.body;
    // Sempre forçar bypassCache para true nesta rota, pois é uma verificação explícita do usuário
    const bypassCache = true;
    const userAgent = req.get("User-Agent") || "";
    const ip = req.realIP || req.ip || req.connection.remoteAddress || "";

    if (!username || username.length < 1) {
        return res.status(400).json({
            success: false,
            error: "Nome de usuário é obrigatório"
        });
    }

    try {
        const shouldBypass = (bypassCache !== undefined) ? bypassCache : true;
        const uname = String(username || '').trim().replace(/^@/, '');
        const traceId = Math.random().toString(36).slice(2, 8);
        const startedAtMs = Date.now();

        const saveSnapshot = async (profile, source) => {
            try {
                if (!profile || !profile.username) return;
                const vu = await getCollection('validated_insta_users');
                const checkedAtIso = new Date().toISOString();
                const doc = {
                    username: String(profile.username).toLowerCase(),
                    fullName: profile.fullName || '',
                    profilePicUrl: profile.profilePicUrl || '',
                    isVerified: !!profile.isVerified,
                    isPrivate: !!profile.isPrivate,
                    followersCount: typeof profile.followersCount === 'number' ? profile.followersCount : 0,
                    checkedAt: checkedAtIso,
                    linkId: (req && req.session) ? req.session.linkSlug : null,
                    ip: String(ip || ''),
                    userAgent: String(userAgent || ''),
                    source: String(source || '').trim() || 'check_privacy',
                };
                const snapshot = { checkedAt: checkedAtIso, followersCount: doc.followersCount, isPrivate: doc.isPrivate, source: doc.source };
                await vu.updateOne(
                    { username: doc.username },
                    { $set: doc, $setOnInsert: { createdAt: new Date().toISOString() }, $push: { checks: { $each: [snapshot], $slice: -60 } } },
                    { upsert: true }
                );
            } catch (_) {}
        };

        try {
            console.log(`🌐 [check-privacy:${traceId}] start @${uname}`);
            console.log(`🌐 [check-privacy:${traceId}] tentando web_profile_info @${uname}`);
            const w = await fetchInstagramFollowersInfo(uname);
            if (w && w.success && w.profile && typeof w.profile.isPrivate === 'boolean') {
                const p = Object.assign({}, w.profile, { checkedAt: w.profile.checkedAt || new Date().toISOString() });
                await saveSnapshot(p, `check_privacy_${p.source || 'web_profile_info'}`);
                console.log(`🌐 [check-privacy:${traceId}] ok source=${String(p.source || 'web_profile_info')} private=${p.isPrivate ? '1' : '0'} fc=${typeof p.followersCount === 'number' ? p.followersCount : ''} ms=${Date.now() - startedAtMs}`);
                return res.json({ success: true, isPrivate: !!p.isPrivate, profile: p });
            }
        } catch (e) {
            try { console.warn(`⚠️ [check-privacy:${traceId}] web_profile_info falhou @${uname}:`, e?.message || String(e)); } catch (_) {}
        }

        if (process.env.ROCKETAPI_TOKEN && (!global.rocketApiDisabledUntil || Date.now() > global.rocketApiDisabledUntil)) {
            try {
                console.log(`🚀 [check-privacy:${traceId}] fallback rocketapi @${uname}`);
                const rocketUrl = 'https://v1.rocketapi.io/instagram/user/get_info';
                const rocketResp = await axios.post(rocketUrl, { username: uname }, {
                    headers: { 'Authorization': `Token ${process.env.ROCKETAPI_TOKEN}` },
                    timeout: 15000
                });
                const rData = rocketResp.data;
                const isRocketOk = rData && (rData.status === 'ok' || rData.status === 'done');
                const rUser = (isRocketOk && rData.response && rData.response.body && rData.response.body.data && rData.response.body.data.user)
                    ? rData.response.body.data.user
                    : null;
                if (rUser && rUser.username) {
                    global.rocketApiDisabledUntil = 0;
                    const profile = {
                        username: rUser.username,
                        fullName: rUser.full_name || '',
                        profilePicUrl: rUser.profile_pic_url_hd || rUser.profile_pic_url || '',
                        followersCount: (rUser.edge_followed_by ? rUser.edge_followed_by.count : 0),
                        isPrivate: !!rUser.is_private,
                        isVerified: !!rUser.is_verified,
                        checkedAt: new Date().toISOString(),
                        source: 'rocketapi'
                    };
                    if (typeof isAllowedImageHost === 'function' && profile.profilePicUrl && isAllowedImageHost(profile.profilePicUrl)) {
                        profile.profilePicUrl = `/image-proxy?url=${encodeURIComponent(profile.profilePicUrl)}`;
                    }
                    await saveSnapshot(profile, 'check_privacy_rocketapi');
                    console.log(`🚀 [check-privacy:${traceId}] ok source=rocketapi private=${profile.isPrivate ? '1' : '0'} fc=${typeof profile.followersCount === 'number' ? profile.followersCount : ''} ms=${Date.now() - startedAtMs}`);
                    return res.json({ success: true, isPrivate: !!profile.isPrivate, profile });
                }
            } catch (eRocket) {
                const msg = String(eRocket?.message || '');
                try { console.warn(`❌ [check-privacy:${traceId}] rocketapi falhou @${uname}:`, msg); } catch (_) {}
                try {
                    const raw = String(eRocket?.response?.data || '');
                    if (raw.toLowerCase().includes('expired')) global.rocketApiDisabledUntil = Date.now() + (10 * 60 * 1000);
                } catch (_) {}
            }
        }

        const result = await verifyInstagramProfile(uname, userAgent, ip, req, res, shouldBypass, { purpose: 'check_privacy', skipPosts: true });
        try {
            const p = result && result.profile ? result.profile : null;
            const src = p ? String(p.source || 'verifyInstagramProfile') : 'verifyInstagramProfile';
            console.log(`🧩 [check-privacy:${traceId}] final source=${src} private=${p && p.isPrivate ? '1' : '0'} fc=${p && typeof p.followersCount === 'number' ? p.followersCount : ''} ms=${Date.now() - startedAtMs}`);
        } catch (_) {}
        return res.json({ success: true, isPrivate: !!(result.profile && result.profile.isPrivate), profile: result.profile });

    } catch (error) {
        console.error("Erro na verificação de privacidade:", error.message);
        return res.status(500).json({
            success: false,
            error: "Erro ao verificar privacidade. Tente novamente."
        });
    }
});

// API para verificar perfil do Instagram (usando API interna)
app.post("/api/check-instagram-profile", async (req, res) => {
    const { username, utms, bypassCache } = req.body;
    const userAgent = req.get("User-Agent") || "";
    const ip = req.realIP || req.ip || req.connection.remoteAddress || "";

    if (!username || username.length < 1) {
        return res.status(400).json({
            success: false,
            error: "Nome de usuário é obrigatório"
        });
    }

    // Verificar Blacklist
    try {
        const blacklistCol = await getCollection('blacklist');
        const blocked = await blacklistCol.findOne({ username: String(username).trim().toLowerCase() });
        if (blocked) {
            return res.status(403).json({
                success: false,
                error: "blocked_user",
                message: "Este usuário está bloqueado no sistema."
            });
        }
    } catch (e) {
        console.error('Erro ao verificar blacklist:', e);
    }

    // Pré-registro idempotente antes de qualquer retorno 409
    try {
      const vuPreAlways = await getCollection('validated_insta_users');
      const preDocAlways = { 
          username: String(username).trim().toLowerCase(), 
          ip: String(ip || ''), 
          userAgent: String(userAgent || ''), 
          source: 'api.check.pre-always', 
          firstSeenAt: new Date().toISOString(),
          utms: utms || {}
      };
      try { await vuPreAlways.updateOne({ username: preDocAlways.username }, { $setOnInsert: preDocAlways, $set: { lastEvent: 'pre-always', lastAt: new Date().toISOString() } }, { upsert: true }); } catch (_) {}
    } catch (_) {}

    // Verificação via Apify (Delegando para função centralizada verifyInstagramProfile)
    try {
        const shouldBypass = (typeof bypassCache !== 'undefined') ? !!bypassCache : false;
        const wantsSkipPosts = !!(req.body && (req.body.skipPosts === true || req.body.skip_posts === true));
        const result = await verifyInstagramProfile(
            username,
            userAgent,
            ip,
            req,
            res,
            shouldBypass,
            wantsSkipPosts ? { purpose: 'profile_check', skipPosts: true } : { purpose: 'profile_check' }
        );

        // Adaptar o retorno para o formato esperado por este endpoint se necessário
        // verifyInstagramProfile já retorna { success, status, profile, error }
        // Se verifyInstagramProfile retornar erro (success: false), devemos repassar o status code apropriado
        
        if (!result.success) {
            try {
              const raw = String(result && result.error ? result.error : '');
              const isIgSession =
                /invalid\s+session\s+token/i.test(raw) ||
                /\big_session_invalid\b/i.test(raw) ||
                /\b(session\s+invalid|session\s+expired)\b/i.test(raw);
              if (isIgSession) {
                return res.status(502).json({
                  success: false,
                  status: 502,
                  error: 'Erro na sessão do Instagram. Tente novamente em alguns instantes.'
                });
              }
            } catch (_) {}
            return res.status(result.status || 500).json(result);
        }

        return res.json(result);

    } catch (error) {
        console.error("❌ Erro no handler check-instagram-profile:", error.message);
        return res.status(500).json({
            success: false,
            error: "Erro interno ao verificar perfil."
        });
    }
});

