app.get('/api/checkout/payment-state', async (req, res) => {
  try {
    try { res.set('Cache-Control', 'no-store'); } catch (_) {}
    const id = String(req.query.id || '').trim();
    const identifier = String(req.query.identifier || '').trim();
    const correlationID = String(req.query.correlationID || '').trim();
    const col = await getCollection('checkout_orders');
    const conds = [];
    
    if (id) {
        conds.push({ 'woovi.chargeId': id });
        conds.push({ 'woovi.id': id });
        conds.push({ 'expay.transactionId': id });
        conds.push({ 'expay.id': id });
        conds.push({ 'paghiper.transactionId': id });
        // Try as ObjectId if valid
        if (/^[0-9a-fA-F]{24}$/.test(id)) {
            const { ObjectId } = require('mongodb');
            try { conds.push({ _id: new ObjectId(id) }); } catch(_) {}
        }
    }
    if (identifier) { 
        conds.push({ 'woovi.identifier': identifier }); 
        conds.push({ 'expay.transactionId': identifier });
        conds.push({ 'expay.identifier': identifier });
        conds.push({ 'paghiper.transactionId': identifier });
        conds.push({ identifier: identifier }); 
    }
    if (correlationID) conds.push({ correlationID });
    
    const filter = conds.length ? { $or: conds } : {};
    const doc = await col.findOne(filter, { projection: { status: 1, woovi: 1, expay: 1, paghiper: 1 } });
    
    let paid = !!doc && (
        /(pago|paid|completed|success|approved|aprovado)/i.test(String(doc.status || '').trim()) ||
        String(doc.woovi?.status || '').toLowerCase() === 'pago' ||
        String(doc.woovi?.status || '').toLowerCase() === 'completed' ||
        String(doc.expay?.status || '').toLowerCase() === 'pago' ||
        String(doc.expay?.status || '').toLowerCase() === 'paid' ||
        String(doc.expay?.status || '').toLowerCase() === 'completed' ||
        /(pago|paid|completed|success|approved|aprovado)/i.test(String(doc.paghiper?.status || '').trim())
    );

    const paghiperApiKey = String(process.env.PAGHIPER_API_KEY || '').trim();
    const paghiperToken = String(process.env.PAGHIPER_TOKEN || '').trim();
    const txId = String((doc && doc.paghiper && doc.paghiper.transactionId) || id || identifier || '').trim();
    const txLooksLikePagHiper = !!txId && /^[A-Z0-9]{12,32}$/.test(txId);
    const shouldTryPagHiperRemoteBase = !paid && txLooksLikePagHiper && !!paghiperApiKey && !!paghiperToken;
    let remote = null;
    if (!paid && txLooksLikePagHiper && (!paghiperApiKey || !paghiperToken)) {
      remote = { ok: false, error: 'missing_paghiper_credentials' };
    }
    if (shouldTryPagHiperRemoteBase) {
      const throttle = global.__oppus_paghiper_status_throttle || (global.__oppus_paghiper_status_throttle = new Map());
      const now = Date.now();
      const last = throttle.get(txId) || 0;
      if (last && now - last < 6500) {
        return res.json({ ok: true, paid, order: doc || null, remote: { ok: true, skipped: true } });
      }
      throttle.set(txId, now);
      try {
        const resp = await axios.post('https://pix.paghiper.com/invoice/status/', { token: paghiperToken, apiKey: paghiperApiKey, transaction_id: txId }, {
          headers: { Accept: 'application/json', 'Content-Type': 'application/json' },
          timeout: 15000
        });
        const data = resp?.data || {};
        const stRoot = data?.status_request || data || {};
        const statusRaw = String(stRoot?.status || '').trim();
        const statusLower = statusRaw.toLowerCase();
        const paidFlag = /(paid|pago|completed|success|approved|aprovado)/i.test(statusLower);
        remote = { ok: true, status: statusLower || statusRaw || '', paid: !!paidFlag };

        if (paidFlag && doc && doc._id) {
          try {
            const setFields = {
              status: 'pago',
              paidAt: new Date().toISOString(),
              'paghiper.statusPayload': data || null,
              'paghiper.status': statusLower || 'paid',
              'paghiper.paidAt': new Date().toISOString()
            };
            await col.updateOne({ _id: doc._id }, { $set: setFields });
            paid = true;
          } catch (_) {
            paid = true;
          }
        } else if (paidFlag) {
          paid = true;
        }
      } catch (err2) {
        const details = err2?.response?.data || { message: err2?.message || String(err2) };
        remote = { ok: false, error: String(details?.message || details?.error || err2?.message || '').trim() || 'remote_check_failed' };
      }
    }
    
    return res.json({ ok: true, paid, order: doc || null, remote });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});
const orderPageHandler = async (req, res) => {
  try {
    const identifier = String(req.query.identifier || req.query.t || '').trim();
     const correlationID = String(req.query.correlationID || req.query.ref || '').trim();
     const sessionId = String(req.query.session_id || req.query.sessionId || '').trim();
     const orderIDRaw = String(req.query.orderID || req.query.orderid || req.query.oid || '').trim();
     const phoneRaw = String(req.query.phone || '').trim();
    const hasQuery = !!(identifier || correlationID || sessionId || orderIDRaw || phoneRaw);
    const hasSessionCtx = !!(req.session && (req.session.selectedOrderID || req.session.lastPaidIdentifier || req.session.lastPaidCorrelationID));
    if (!hasQuery && !hasSessionCtx) {
      return res.redirect('/customer');
    }
    const col = await getCollection('checkout_orders');
    let doc = null;
    // 1) Se houver parâmetros na URL, priorizar sempre a busca por eles
    if (hasQuery) {
      const conds = [];
      if (identifier) { conds.push({ 'woovi.identifier': identifier }); conds.push({ 'expay.transactionId': identifier }); conds.push({ 'paghiper.transactionId': identifier }); conds.push({ identifier }); }
      if (correlationID) conds.push({ correlationID });
      if (sessionId) { conds.push({ 'stripe.checkout_session_id': sessionId }); conds.push({ identifier: sessionId }); }
      if (orderIDRaw) {
        const maybeNum = Number(orderIDRaw);
        if (!Number.isNaN(maybeNum)) {
          conds.push({ 'fama24h.orderId': maybeNum });
          conds.push({ 'fama24h_multi.orders.orderId': maybeNum });
          conds.push({ 'fornecedor_social.orderId': maybeNum });
        }
        conds.push({ 'fama24h.orderId': orderIDRaw });
        conds.push({ 'fama24h_multi.orders.orderId': orderIDRaw });
        conds.push({ 'fornecedor_social.orderId': orderIDRaw });
        // Support woovi.chargeId
        conds.push({ 'woovi.chargeId': orderIDRaw });
        conds.push({ 'woovi.id': orderIDRaw });
        conds.push({ 'expay.transactionId': orderIDRaw });
        conds.push({ 'paghiper.transactionId': orderIDRaw });
        
        const { ObjectId } = require('mongodb');
        if (/^[0-9a-fA-F]{24}$/.test(orderIDRaw)) {
             try { conds.push({ _id: new ObjectId(orderIDRaw) }); } catch(_) {}
        }
      }
      if (phoneRaw) {
        const digits = phoneRaw.replace(/\D/g, '');
        if (digits) {
          conds.push({ 'customer.phone': `+55${digits}` });
          conds.push({ additionalInfo: { $elemMatch: { key: 'phone', value: digits } } });
        }
      }
      if (conds.length) {
        doc = await col.findOne({ $or: conds });
      }
    }
    // 2) Se não veio query ou ela não encontrou nada, usar pedido selecionado em sessão
    if (!doc && req.session && req.session.selectedOrderID) {
      const soid = req.session.selectedOrderID;
      const { ObjectId } = require('mongodb');
      const orConds = [ { 'fama24h.orderId': soid }, { 'fama24h_multi.orders.orderId': soid }, { 'fornecedor_social.orderId': soid } ];
      if (typeof soid === 'string' && /^[0-9a-fA-F]{24}$/.test(soid)) {
        try { orConds.push({ _id: new ObjectId(soid) }); } catch(_) {}
      }
      doc = await col.findOne({ $or: orConds });
    }
    // 3) Por último, usar último pago guardado em sessão (apenas se recente)
    if (!doc && req.session && (req.session.lastPaidIdentifier || req.session.lastPaidCorrelationID)) {
      const markedAt = Number(req.session.lastPaidMarkedAt || 0);
      const isFresh = markedAt && ((Date.now() - markedAt) <= (30 * 60 * 1000));
      if (isFresh) {
        const lpId = String(req.session.lastPaidIdentifier || '').trim();
        const lpCorr = String(req.session.lastPaidCorrelationID || '').trim();
        const firstConds = [];
        if (lpId) { firstConds.push({ 'woovi.identifier': lpId }); firstConds.push({ 'expay.transactionId': lpId }); firstConds.push({ identifier: lpId }); }
        if (lpCorr) firstConds.push({ correlationID: lpCorr });
        if (firstConds.length) {
          const paidFilter = { $and: [ { $or: firstConds }, { $or: [ { status: 'pago' }, { 'woovi.status': 'pago' }, { 'expay.status': 'pago' } ] } ] };
          try {
            const arr = await col.find(paidFilter).sort({ 'woovi.paidAt': -1, 'expay.paidAt': -1, paidAt: -1 }).limit(1).toArray();
            doc = (Array.isArray(arr) && arr.length) ? arr[0] : null;
          } catch (_) {
            doc = await col.findOne({ $or: firstConds });
          }
        }
      }
    }

    if (doc) {
      try {
        const additionalInfoMap = doc.additionalInfoMapPaid || (Array.isArray(doc.additionalInfoPaid) ? doc.additionalInfoPaid.reduce((acc, it) => { acc[it.key] = it.value; return acc; }, {}) : (Array.isArray(doc.additionalInfo) ? doc.additionalInfo.reduce((acc, it) => { acc[it.key] = it.value; return acc; }, {}) : {}));
        const tipo0 = String(additionalInfoMap['tipo_servico'] || doc.tipo || doc.tipoServico || '').toLowerCase();
        const cat0 = String(additionalInfoMap['categoria_servico'] || '').toLowerCase();
        const pacote0 = String(additionalInfoMap['pacote'] || '').toLowerCase();
        const isCurtidasBase0 = cat0 === 'curtidas' || cat0 === 'curtidas_brasileiras' || pacote0.includes('curtida');
        const isCurtidasOrganicos0 = isCurtidasBase0 && /(organicos|curtidas_reais|curtidas_organicos)/i.test(tipo0);
        if (isCurtidasOrganicos0 && doc.fama24h) {
          try { await col.updateOne({ _id: doc._id }, { $unset: { fama24h: '' } }); } catch (_) {}
          try { delete doc.fama24h; } catch (_) {}
        }
        const fs = doc.fornecedor_social || null;
        const fsOrderId = fs && fs.orderId ? fs.orderId : null;
        const fsStatus = String(fs && fs.status ? fs.status : '').toLowerCase();
        const fsAttemptedAtMs = fs && fs.attemptedAt ? new Date(String(fs.attemptedAt)).getTime() : 0;
        const shouldRetry = isCurtidasOrganicos0 && !fsOrderId && (fsStatus === 'processing') && fsAttemptedAtMs && ((Date.now() - fsAttemptedAtMs) > (3 * 60 * 1000));
        if (shouldRetry) {
          processOrderFulfillment(doc, col, req).catch(() => {});
        }
      } catch (_) {}
    }

    if (doc && sessionId) {
      const status0 = String(doc.status || '').trim().toLowerCase();
      const isPaid0 = status0 === 'pago';
      const hasStripe0 = !!(doc.stripe && (doc.stripe.checkout_session_id || doc.stripe.payment_intent_id));
      if (!isPaid0 && hasStripe0) {
        try {
          const stripeKeys = getStripeKeys();
          const stripeSecret = String(stripeKeys.secret || '').trim();
          if (stripeSecret) {
            const sessResp = await axios.get(`https://api.stripe.com/v1/checkout/sessions/${encodeURIComponent(sessionId)}`, {
              headers: { 'Authorization': `Bearer ${stripeSecret}` },
              timeout: 15000
            });
            const sess = sessResp && sessResp.data ? sessResp.data : null;
            const paymentStatus = String(sess?.payment_status || '').trim().toLowerCase();
            const piId = String(sess?.payment_intent || '').trim();
            const isPaid = paymentStatus === 'paid';
            if (isPaid) {
              const set = {
                status: 'pago',
                paidAt: doc.paidAt || new Date().toISOString(),
                stripe: Object.assign({}, doc.stripe || {}, {
                  environment: stripeKeys.useTest ? 'test' : 'live',
                  checkout_session_id: String(sess?.id || sessionId),
                  payment_intent_id: piId || (doc.stripe && doc.stripe.payment_intent_id) || '',
                  status: paymentStatus || 'paid'
                })
              };
              await col.updateOne({ _id: doc._id }, { $set: set });
              doc = Object.assign({}, doc, set);
              try { await processOrderFulfillment(doc, col, req); } catch (_) {}
            }
          }
        } catch (_) {}
      }
    }
    
    // Garantir que o link de refil exista para este pedido (para o botão "Acessar ferramenta")
    if (doc) {
      try {
        if (!doc.refilLinkId) {
            // Tentar gerar/recuperar link se não existir
            const rLink = await ensureRefilLink(doc.identifier || doc['woovi.identifier'] || '', doc.correlationID || '', req);
            if (rLink && rLink.id) {
                doc.refilLinkId = rLink.id;
            }
        }
      } catch (errLink) {
        try { console.warn('Falha ao garantir refilLink em /pedido', errLink.message); } catch(_) {}
      }
    }

    const order = doc || {};
    let refilDaysLeft = null;
    try {
      const token = order && order.refilLinkId ? String(order.refilLinkId).trim() : '';
      if (token) {
        const tl = await getCollection('temporary_links');
        const linkRec = await tl.findOne({ id: token }, { projection: { createdAt: 1, expiresAt: 1, warrantyMode: 1, warrantyDays: 1 } });
        const isLifetime = String(linkRec?.warrantyMode || '').toLowerCase() === 'life';
        if (!isLifetime) {
          const brtOffsetMs = 3 * 60 * 60 * 1000;
          const dayMs = 24 * 60 * 60 * 1000;
          const brtYmdFromMs = (ms) => {
            const d = new Date(Number(ms || 0) - brtOffsetMs);
            return { y: d.getUTCFullYear(), m: d.getUTCMonth() + 1, d: d.getUTCDate() };
          };
          const dayNumFromYmd = (y, m, d) => Math.floor(Date.UTC(Number(y), Number(m) - 1, Number(d)) / dayMs);
          const nowYmd = brtYmdFromMs(Date.now());
          const nowDay = dayNumFromYmd(nowYmd.y, nowYmd.m, nowYmd.d);
          if (linkRec?.expiresAt) {
            const expMs = new Date(String(linkRec.expiresAt)).getTime();
            if (Number.isFinite(expMs) && expMs > 0) {
              const expYmd = brtYmdFromMs(expMs);
              const expDay = dayNumFromYmd(expYmd.y, expYmd.m, expYmd.d);
              refilDaysLeft = Math.max(0, expDay - nowDay);
            }
          }
        }
      }
    } catch (_) {}
    try {
      const map = order && order.additionalInfoMapPaid ? order.additionalInfoMapPaid : {};
      let uname = String(map['instagram_username'] || '').trim();
      if (!uname) uname = String(order.instagramUsername || order.instauser || '').trim();
      
      // Sempre verificar status mais recente no banco de validação
      if (uname) {
        const vu = await getCollection('validated_insta_users');
        const vUser = await vu.findOne({ username: String(uname).trim().toLowerCase() });
        
        // Atualizar em background se não existir ou se for antigo (> 1 hora)
        const nowMs = Date.now();
        const lastCheck = vUser && vUser.checkedAt ? new Date(vUser.checkedAt).getTime() : 0;
        const isOld = (nowMs - lastCheck) > (60 * 60 * 1000);
        
        if (!vUser || isOld) {
             const mockReq = { session: {}, query: {}, body: {} };
             // Disparar verificação sem aguardar (fire-and-forget) para não travar o carregamento
             verifyInstagramProfile(uname, 'Background-Pedido', req.ip || '127.0.0.1', mockReq, null)
                 .catch(err => { try { console.error('❌ [pedido] Falha ao atualizar perfil Instagram em background:', err.message); } catch(_) {} });
        }

        if (vUser) {
            // Se o banco diz que é privado, forçar status privado
            // Se o banco diz que é público, atualizar também (caso o usuário tenha aberto)
            order.profilePrivacy = { 
                username: uname, 
                isPrivate: !!vUser.isPrivate, 
                checkedAt: vUser.checkedAt,
                source: 'db_fresh_check' 
            };
            if (typeof vUser.followersCount === 'number') order.followersCount = vUser.followersCount;
        }
      }
    } catch (_) {}
    return res.render('pedido', { order, refilDaysLeft, PIXEL_ID: process.env.PIXEL_ID || '', logoLink: '/engagement' });
  } catch (e) {
    return res.status(500).type('text/plain').send('Erro ao carregar pedido');
  }
};

